function Countdown() {
  const [t, setT] = useState({d:0,h:0,m:0,s:0});
  useEffect(() => {
    const calc = () => {
      const now = new Date(), end = new Date(now.getFullYear(), now.getMonth()+1, 1);
      const d = Math.max(0, end - now);
      return {d:Math.floor(d/864e5),h:Math.floor(d%864e5/36e5),m:Math.floor(d%36e5/6e4),s:Math.floor(d%6e4/1e3)};
    };
    setT(calc());
    const id = setInterval(() => setT(calc()), 1000);
    return () => clearInterval(id);
  }, []);
  return (
    <div style={{display:"flex",gap:12,justifyContent:"center"}}>
      {[["DAYS",t.d],["HRS",t.h],["MIN",t.m],["SEC",t.s]].map(([l,v]) => (
        <div key={l} style={{textAlign:"center",background:"rgba(0,200,83,0.06)",border:"1px solid rgba(0,200,83,0.15)",borderRadius:10,padding:"10px 14px",minWidth:56}}>
          <div style={{fontSize:28,fontWeight:800,color:"#fff",fontFamily:"'Bebas Neue',sans-serif",letterSpacing:2,lineHeight:1}}>{String(v).padStart(2,"0")}</div>
          <div style={{fontSize:9,fontWeight:600,letterSpacing:2,color:C.textMuted,marginTop:4}}>{l}</div>
        </div>
      ))}
    </div>
  );
}

